   228â†’func TestHandleLifecycleTurnEnd_EmptyRepository(t *testing.T) {
   229â†’	// Cannot use t.Parallel() because we use t.Chdir()
   230â†’	tmpDir := t.TempDir()
   231â†’	t.Chdir(tmpDir)
   232â†’
   233â†’	// Initialize an empty git repo (no commits)
   234â†’	if err := os.MkdirAll(".git/objects", 0o755); err != nil {
   235â†’		t.Fatalf("Failed to create .git: %v", err)
   236â†’	}
   237â†’	if err := os.WriteFile(".git/HEAD", []byte("ref: refs/heads/main\n"), 0o644); err != nil {
   238â†’		t.Fatalf("Failed to create HEAD: %v", err)
   239â†’	}
   240â†’	paths.ClearRepoRootCache()
   241â†’
   242â†’	// Create a transcript file
   243â†’	transcriptPath := filepath.Join(tmpDir, "transcript.jsonl")
   244â†’	if err := os.WriteFile(transcriptPath, []byte(`{"type":"user","message":"test"}`+"\n"), 0o644); err != nil {
   245â†’		t.Fatalf("Failed to create transcript: %v", err)
   246â†’	}
   247â†’
   248â†’	ag := newMockAgent()
   249â†’	event := &agent.Event{
   250â†’		Type:       agent.TurnEnd,
   251â†’		SessionID:  "test-session",
   252â†’		SessionRef: transcriptPath,
   253â†’	}
   254â†’
   255â†’	err := handleLifecycleTurnEnd(ag, event)
   256â†’
   257â†’	// Should return a SilentError wrapping ErrEmptyRepository
   258â†’	if err == nil {
   259â†’		t.Error("expected error for empty repository, got nil")
   260â†’	}
   261â†’
   262â†’	var silentErr *SilentError
   263â†’	if !errors.As(err, &silentErr) {
   264â†’		t.Errorf("expected SilentError, got: %T", err)
   265â†’	}
   266â†’	if !errors.Is(silentErr.Unwrap(), strategy.ErrEmptyRepository) {
   267â†’		t.Errorf("expected ErrEmptyRepository, got: %v", silentErr.Unwrap())
   268â†’	}
   269â†’}
