   475â†’func TestDispatchLifecycleEvent_RoutesToCorrectHandler(t *testing.T) {
   476â†’	t.Parallel()
   477â†’
   478â†’	// Test that each event type is routed (we can't easily verify which handler
   479â†’	// was called without dependency injection, but we can verify no panic and
   480â†’	// expected error types for each event type with minimal required data)
   481â†’
   482â†’	testCases := []struct {
   483â†’		name        string
   484â†’		eventType   agent.EventType
   485â†’		sessionID   string
   486â†’		expectError bool
   487â†’		errorSubstr string
   488â†’	}{
   489â†’		{
   490â†’			name:        "SessionStart with empty session ID",
   491â†’			eventType:   agent.SessionStart,
   492â†’			sessionID:   "",
   493â†’			expectError: true,
   494â†’			errorSubstr: "no session_id",
   495â†’		},
   496â†’		{
   497â†’			name:        "TurnStart with empty session ID",
   498â†’			eventType:   agent.TurnStart,
   499â†’			sessionID:   "",
   500â†’			expectError: true,
   501â†’			errorSubstr: "no session_id",
   502â†’		},
   503â†’		{
   504â†’			name:        "TurnEnd with empty transcript",
   505â†’			eventType:   agent.TurnEnd,
   506â†’			sessionID:   "test",
   507â†’			expectError: true,
   508â†’			errorSubstr: "transcript file not found",
   509â†’		},
   510â†’		{
   511â†’			name:        "Compaction with empty transcript is no-op",
   512â†’			eventType:   agent.Compaction,
   513â†’			sessionID:   "test",
   514â†’			expectError: false, // Compaction just resets offset; doesn't read transcript
   515â†’		},
   516â†’		{
   517â†’			name:        "SessionEnd with empty session ID is no-op",
