   237â†’// --- Transcript flush sentinel ---
   238â†’
   239â†’// stopHookSentinel is the string that appears in Claude Code's hook_progress
   240â†’// entry when the stop hook has been invoked, indicating the transcript is fully flushed.
   241â†’const stopHookSentinel = "hooks claude-code stop"
   242â†’
   243â†’// waitForTranscriptFlush polls the transcript file for the stop hook sentinel.
   244â†’// Falls back silently after a timeout.
   245â†’func waitForTranscriptFlush(transcriptPath string, hookStartTime time.Time) {
   246â†’	const (
   247â†’		maxWait      = 3 * time.Second
   248â†’		pollInterval = 50 * time.Millisecond
   249â†’		tailBytes    = 4096
   250â†’		maxSkew      = 2 * time.Second
   251â†’	)
   252â†’
   253â†’	logCtx := logging.WithComponent(context.Background(), "agent.claudecode")
   254â†’	deadline := time.Now().Add(maxWait)
   255â†’	for time.Now().Before(deadline) {
   256â†’		if checkStopSentinel(transcriptPath, tailBytes, hookStartTime, maxSkew) {
   257â†’			logging.Debug(logCtx, "transcript flush sentinel found",
   258â†’				slog.Duration("wait", time.Since(hookStartTime)),
   259â†’			)
   260â†’			return
   261â†’		}
   262â†’		time.Sleep(pollInterval)
   263â†’	}
   264â†’	logging.Warn(logCtx, "transcript flush sentinel not found within timeout, proceeding",
   265â†’		slog.Duration("timeout", maxWait),
   266â†’	)
   267â†’}
   268â†’
   269â†’// checkStopSentinel reads the tail of the transcript file and looks for the sentinel.
   270â†’func checkStopSentinel(path string, tailBytes int64, hookStartTime time.Time, maxSkew time.Duration) bool {
   271â†’	f, err := os.Open(path) //nolint:gosec // path comes from agent hook input
   272â†’	if err != nil {
   273â†’		return false
   274â†’	}
   275â†’	defer f.Close()
   276â†’
   277â†’	info, err := f.Stat()
   278â†’	if err != nil {
   279â†’		return false
   280â†’	}
   281â†’	offset := info.Size() - tailBytes
   282â†’	if offset < 0 {
   283â†’		offset = 0
   284â†’	}
   285â†’	buf := make([]byte, info.Size()-offset)
   286â†’	if _, err := f.ReadAt(buf, offset); err != nil {
   287â†’		return false
   288â†’	}
   289â†’
   290â†’	lines := strings.Split(string(buf), "\n")
   291â†’	for _, line := range lines {
   292â†’		line = strings.TrimSpace(line)
   293â†’		if line == "" || !strings.Contains(line, stopHookSentinel) {
   294â†’			continue
   295â†’		}
   296â†’
   297â†’		var entry struct {
   298â†’			Timestamp string `json:"timestamp"`
   299â†’		}
   300â†’		if json.Unmarshal([]byte(line), &entry) != nil || entry.Timestamp == "" {
   301â†’			continue
   302â†’		}
   303â†’		ts, err := time.Parse(time.RFC3339Nano, entry.Timestamp)
   304â†’		if err != nil {
   305â†’			ts, err = time.Parse(time.RFC3339, entry.Timestamp)
   306â†’			if err != nil {
   307â†’				continue
   308â†’			}
   309â†’		}
   310â†’		cutoff := hookStartTime.Add(-maxSkew)
   311â†’		if ts.After(cutoff) {
   312â†’			return true
   313â†’		}
   314â†’	}
   315â†’	return false
   316â†’}
