    84â†’// CapturePrePromptState captures current untracked files and transcript position before a prompt
    85â†’// and saves them to a state file.
    86â†’//
    87â†’// The agent parameter is used to determine the transcript position via TranscriptAnalyzer.
    88â†’// If the agent does not implement TranscriptAnalyzer, the transcript offset will be 0.
    89â†’// The sessionRef parameter is optional â€” if empty, transcript position won't be captured.
    90â†’//
    91â†’// Works correctly from any subdirectory within the repository.
    92â†’func CapturePrePromptState(ag agent.Agent, sessionID, sessionRef string) error {
    93â†’	if sessionID == "" {
    94â†’		sessionID = unknownSessionID
    95â†’	}
    96â†’
    97â†’	// Get absolute path for tmp directory
    98â†’	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
    99â†’	if err != nil {
   100â†’		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
   101â†’	}
   102â†’
   103â†’	// Create tmp directory if it doesn't exist
   104â†’	if err := os.MkdirAll(tmpDirAbs, 0o750); err != nil {
   105â†’		return fmt.Errorf("failed to create tmp directory: %w", err)
   106â†’	}
   107â†’
   108â†’	// Get list of untracked files (excluding .entire directory itself)
   109â†’	untrackedFiles, err := getUntrackedFilesForState()
   110â†’	if err != nil {
   111â†’		return fmt.Errorf("failed to get untracked files: %w", err)
   112â†’	}
   113â†’
   114â†’	// Get transcript position using TranscriptAnalyzer if available
   115â†’	var transcriptOffset int
   116â†’	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok && sessionRef != "" {
   117â†’		pos, posErr := analyzer.GetTranscriptPosition(sessionRef)
   118â†’		if posErr != nil {
   119â†’			fmt.Fprintf(os.Stderr, "Warning: failed to get transcript position: %v\n", posErr)
   120â†’		} else {
   121â†’			transcriptOffset = pos
   122â†’		}
   123â†’	}
   124â†’
   125â†’	// Create state file
   126â†’	stateFile := prePromptStateFile(sessionID)
   127â†’	state := PrePromptState{
   128â†’		SessionID:        sessionID,
   129â†’		Timestamp:        time.Now().UTC().Format(time.RFC3339),
   130â†’		UntrackedFiles:   untrackedFiles,
   131â†’		TranscriptOffset: transcriptOffset,
   132â†’	}
   133â†’
   134â†’	data, err := jsonutil.MarshalIndentWithNewline(state, "", "  ")
   135â†’	if err != nil {
   136â†’		return fmt.Errorf("failed to marshal state: %w", err)
   137â†’	}
   138â†’
   139â†’	if err := os.WriteFile(stateFile, data, 0o600); err != nil {
   140â†’		return fmt.Errorf("failed to write state file: %w", err)
   141â†’	}
   142â†’
   143â†’	fmt.Fprintf(os.Stderr, "Captured state before prompt: %d untracked files, transcript offset: %d\n",
   144â†’		len(untrackedFiles), transcriptOffset)
   145â†’	return nil
   146â†’}
