   181â†’// FileChanges holds categorized file changes from git status.
   182â†’type FileChanges struct {
   183â†’	Modified []string // Modified or staged files
   184â†’	New      []string // Untracked files (filtered if previouslyUntracked provided)
   185â†’	Deleted  []string // Deleted files (staged or unstaged)
