   188â†’// DetectFileChanges returns categorized file changes from the current git status.
   189â†’//
   190â†’// previouslyUntracked controls new-file detection:
   191â†’//   - nil: all untracked files go into New
   192â†’//   - non-nil: only untracked files NOT in the pre-existing set go into New
   193â†’//
   194â†’// Modified includes both worktree and staging modified/added files.
   195â†’// Deleted includes both staged and unstaged deletions.
   196â†’// All results exclude .entire/ directory.
   197â†’func DetectFileChanges(previouslyUntracked []string) (*FileChanges, error) {
   198â†’	repo, err := openRepository()
   199â†’	if err != nil {
   200â†’		return nil, fmt.Errorf("failed to open repository: %w", err)
   201â†’	}
   202â†’
   203â†’	worktree, err := repo.Worktree()
   204â†’	if err != nil {
   205â†’		return nil, fmt.Errorf("failed to get worktree: %w", err)
   206â†’	}
   207â†’
   208â†’	status, err := worktree.Status()
   209â†’	if err != nil {
   210â†’		return nil, fmt.Errorf("failed to get status: %w", err)
   211â†’	}
   212â†’
   213â†’	// Build set of pre-existing untracked files for quick lookup
   214â†’	var preExisting map[string]bool
   215â†’	if previouslyUntracked != nil {
   216â†’		preExisting = make(map[string]bool, len(previouslyUntracked))
   217â†’		for _, f := range previouslyUntracked {
   218â†’			preExisting[f] = true
   219â†’		}
   220â†’	}
   221â†’
   222â†’	var changes FileChanges
   223â†’	for file, st := range status {
   224â†’		if paths.IsInfrastructurePath(file) {
   225â†’			continue
   226â†’		}
   227â†’
   228â†’		switch {
   229â†’		case st.Worktree == git.Untracked:
   230â†’			if preExisting != nil {
   231â†’				if !preExisting[file] {
   232â†’					changes.New = append(changes.New, file)
   233â†’				}
   234â†’			} else {
   235â†’				changes.New = append(changes.New, file)
   236â†’			}
   237â†’		case st.Worktree == git.Deleted || st.Staging == git.Deleted:
   238â†’			changes.Deleted = append(changes.Deleted, file)
   239â†’		case st.Worktree == git.Modified || st.Staging == git.Modified ||
   240â†’			st.Worktree == git.Added || st.Staging == git.Added:
   241â†’			changes.Modified = append(changes.Modified, file)
   242â†’		}
   243â†’	}
   244â†’
   245â†’	return &changes, nil
   246â†’}
