   248â†’// FilterAndNormalizePaths converts absolute paths to relative and filters out
   249â†’// infrastructure paths and paths outside the repo.
   250â†’func FilterAndNormalizePaths(files []string, cwd string) []string {
   251â†’	var result []string
   252â†’	for _, file := range files {
   253â†’		relPath := paths.ToRelativePath(file, cwd)
   254â†’		if relPath == "" {
   255â†’			continue // outside repo
   256â†’		}
   257â†’		if paths.IsInfrastructurePath(relPath) {
   258â†’			continue // skip .entire directory
   259â†’		}
   260â†’		result = append(result, relPath)
   261â†’	}
   262â†’	return result
   263â†’}
