   404â†’func preTaskStateFile(toolUseID string) string {
   405â†’	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
   406â†’	if err != nil {
   407â†’		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
