   412â†’// preTaskFilePrefix is the prefix for pre-task state files
   413â†’const preTaskFilePrefix = "pre-task-"
   414â†’
   415â†’// FindActivePreTaskFile finds an active pre-task file in .entire/tmp/ and returns
   416â†’// the parent Task's tool_use_id. Returns ("", false) if no pre-task file exists.
   417â†’// When multiple pre-task files exist (nested subagents), returns the most recently
   418â†’// modified one.
   419â†’// Works correctly from any subdirectory within the repository.
   420â†’func FindActivePreTaskFile() (taskToolUseID string, found bool) {
   421â†’	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
   422â†’	if err != nil {
   423â†’		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
   424â†’	}
   425â†’	entries, err := os.ReadDir(tmpDirAbs)
   426â†’	if err != nil {
   427â†’		return "", false
   428â†’	}
   429â†’
   430â†’	var latestFile string
   431â†’	var latestTime time.Time
   432â†’
   433â†’	for _, entry := range entries {
   434â†’		if entry.IsDir() {
   435â†’			continue
   436â†’		}
   437â†’		name := entry.Name()
   438â†’		if !strings.HasPrefix(name, preTaskFilePrefix) || !strings.HasSuffix(name, ".json") {
   439â†’			continue
   440â†’		}
   441â†’
   442â†’		// Check modification time for nested subagent handling
   443â†’		info, err := entry.Info()
   444â†’		if err != nil {
   445â†’			continue
   446â†’		}
   447â†’		if latestFile == "" || info.ModTime().After(latestTime) {
   448â†’			latestFile = name
   449â†’			latestTime = info.ModTime()
   450â†’		}
   451â†’	}
   452â†’
   453â†’	if latestFile == "" {
   454â†’		return "", false
   455â†’	}
   456â†’
   457â†’	// Extract tool_use_id from filename: pre-task-<tool_use_id>.json
   458â†’	toolUseID := strings.TrimPrefix(latestFile, preTaskFilePrefix)
   459â†’	toolUseID = strings.TrimSuffix(toolUseID, ".json")
   460â†’	return toolUseID, true
   461â†’}
