   463â†’// GetNextCheckpointSequence returns the next sequence number for incremental checkpoints.
   464â†’// It counts existing checkpoint files in the task metadata checkpoints directory.
   465â†’// Returns 1 if no checkpoints exist yet.
   466â†’func GetNextCheckpointSequence(sessionID, taskToolUseID string) int {
   467â†’	// Use the session ID directly as the metadata directory name
   468â†’	sessionMetadataDir := paths.SessionMetadataDirFromSessionID(sessionID)
   469â†’	taskMetadataDir := strategy.TaskMetadataDir(sessionMetadataDir, taskToolUseID)
   470â†’	checkpointsDir := filepath.Join(taskMetadataDir, "checkpoints")
   471â†’
   472â†’	entries, err := os.ReadDir(checkpointsDir)
   473â†’	if err != nil {
   474â†’		// Directory doesn't exist or can't be read - start at 1
   475â†’		return 1
   476â†’	}
   477â†’
   478â†’	// Count JSON files (checkpoints)
   479â†’	count := 0
   480â†’	for _, entry := range entries {
   481â†’		if !entry.IsDir() && strings.HasSuffix(entry.Name(), ".json") {
   482â†’			count++
   483â†’		}
   484â†’	}
   485â†’
   486â†’	return count + 1
   487â†’}
