    23â†’// PhaseFromString normalizes a phase string, treating empty or unknown values
    24â†’// as PhaseIdle for backward compatibility with pre-state-machine session files.
    25â†’func PhaseFromString(s string) Phase {
    26â†’	switch Phase(s) {
    27â†’	case PhaseActive, "active_committed":
    28â†’		// "active_committed" was removed with the 1:1 checkpoint model.
    29â†’		// It previously meant "agent active + commit happened during turn".
    30â†’		// Normalize to ACTIVE so HandleTurnEnd can finalize any pending checkpoints.
    31â†’		return PhaseActive
    32â†’	case PhaseIdle:
    33â†’		return PhaseIdle
    34â†’	case PhaseEnded:
    35â†’		return PhaseEnded
    36â†’	default:
