   127â†’
   128â†’// Transition computes the next phase and required actions given the current
   129â†’// phase and an event. This is a pure function with no side effects.
   130â†’//
   131â†’// Empty or unknown phase values are normalized to PhaseIdle for backward
   132â†’// compatibility with session state files created before phase tracking.
   133â†’func Transition(current Phase, event Event, ctx TransitionContext) TransitionResult {
   134â†’	// Normalize empty/unknown phase to idle for backward compatibility.
   135â†’	current = PhaseFromString(string(current))
   136â†’
   137â†’	switch current {
   138â†’	case PhaseIdle:
   139â†’		return transitionFromIdle(event, ctx)
   140â†’	case PhaseActive:
   141â†’		return transitionFromActive(event, ctx)
   142â†’	case PhaseEnded:
   143â†’		return transitionFromEnded(event, ctx)
   144â†’	default:
   145â†’		// PhaseFromString guarantees we only get known phases, but the
   146â†’		// exhaustive linter requires handling the default case.
   147â†’		return TransitionResult{NewPhase: PhaseIdle}
   148â†’	}
   149â†’}
