   151â†’func transitionFromIdle(event Event, ctx TransitionContext) TransitionResult {
   152â†’	switch event {
   153â†’	case EventTurnStart:
   154â†’		return TransitionResult{
   155â†’			NewPhase: PhaseActive,
   156â†’			Actions:  []Action{ActionUpdateLastInteraction},
   157â†’		}
   158â†’	case EventTurnEnd:
   159â†’		// Turn end while idle is a no-op (no active turn to end).
   160â†’		return TransitionResult{NewPhase: PhaseIdle}
   161â†’	case EventGitCommit:
   162â†’		if ctx.IsRebaseInProgress {
   163â†’			return TransitionResult{NewPhase: PhaseIdle}
   164â†’		}
   165â†’		return TransitionResult{
   166â†’			NewPhase: PhaseIdle,
   167â†’			Actions:  []Action{ActionCondense, ActionUpdateLastInteraction},
   168â†’		}
   169â†’	case EventSessionStart:
   170â†’		// Already condensable, no-op.
   171â†’		return TransitionResult{NewPhase: PhaseIdle}
   172â†’	case EventSessionStop:
   173â†’		return TransitionResult{
   174â†’			NewPhase: PhaseEnded,
   175â†’			Actions:  []Action{ActionUpdateLastInteraction},
   176â†’		}
   177â†’	case EventCompaction:
