   179â†’		return TransitionResult{
   180â†’			NewPhase: PhaseIdle,
   181â†’			Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
   182â†’		}
   183â†’	default:
   184â†’		return TransitionResult{NewPhase: PhaseIdle}
   185â†’	}
   186â†’}
