   271â†’// ActionHandler defines strategy-specific side effects for state transitions.
   272â†’// The compiler enforces that every strategy-specific action has a handler.
   273â†’type ActionHandler interface {
   274â†’	HandleCondense(state *State) error
   275â†’	HandleCondenseIfFilesTouched(state *State) error
