   289â†’// ApplyTransition applies a TransitionResult to state: sets the new phase
   290â†’// unconditionally, then executes all actions. Common actions
   291â†’// (UpdateLastInteraction, ClearEndedAt) always run regardless of handler
   292â†’// errors so that bookkeeping fields stay consistent with the new phase.
   293â†’// Strategy-specific handler actions stop on the first error; subsequent
   294â†’// handler actions are skipped but common actions continue. Returns the
   295â†’// first handler error, or nil.
   296â†’func ApplyTransition(state *State, result TransitionResult, handler ActionHandler) error {
   297â†’	state.Phase = result.NewPhase
   298â†’
   299â†’	var handlerErr error
   300â†’	for _, action := range result.Actions {
   301â†’		switch action {
   302â†’		// Common actions: always applied, even after a handler error.
   303â†’		case ActionUpdateLastInteraction:
   304â†’			now := time.Now()
   305â†’			state.LastInteractionTime = &now
   306â†’		case ActionClearEndedAt:
   307â†’			state.EndedAt = nil
   308â†’
   309â†’		// Strategy-specific actions: skip remaining after the first handler error.
   310â†’		case ActionCondense:
   311â†’			if handlerErr == nil {
   312â†’				if err := handler.HandleCondense(state); err != nil {
   313â†’					handlerErr = fmt.Errorf("%s: %w", action, err)
   314â†’				}
   315â†’			}
   316â†’		case ActionCondenseIfFilesTouched:
   317â†’			if handlerErr == nil {
   318â†’				if err := handler.HandleCondenseIfFilesTouched(state); err != nil {
   319â†’					handlerErr = fmt.Errorf("%s: %w", action, err)
   320â†’				}
   321â†’			}
   322â†’		case ActionDiscardIfNoFiles:
   323â†’			if handlerErr == nil {
   324â†’				if err := handler.HandleDiscardIfNoFiles(state); err != nil {
   325â†’					handlerErr = fmt.Errorf("%s: %w", action, err)
   326â†’				}
   327â†’			}
   328â†’		case ActionWarnStaleSession:
   329â†’			if handlerErr == nil {
   330â†’				if err := handler.HandleWarnStaleSession(state); err != nil {
   331â†’					handlerErr = fmt.Errorf("%s: %w", action, err)
   332â†’				}
   333â†’			}
   334â†’		default:
   335â†’			if handlerErr == nil {
   336â†’				handlerErr = fmt.Errorf("unhandled action: %s", action)
   337â†’			}
   338â†’		}
   339â†’	}
   340â†’	return handlerErr
   341â†’}
