   343â†’// MermaidDiagram generates a Mermaid state diagram from the transition table.
   344â†’// The diagram is derived by calling Transition() for representative context
   345â†’// variants per phase/event, so it stays in sync with the implementation.
   346â†’func MermaidDiagram() string {
   347â†’	var b strings.Builder
   348â†’	b.WriteString("stateDiagram-v2\n")
   349â†’
   350â†’	// State declarations with descriptions.
   351â†’	b.WriteString("    state \"IDLE\" as idle\n")
   352â†’	b.WriteString("    state \"ACTIVE\" as active\n")
   353â†’	b.WriteString("    state \"ENDED\" as ended\n")
   354â†’	b.WriteString("\n")
   355â†’
   356â†’	// Context variants for GitCommit: rebase, files/no-files.
   357â†’	type contextVariant struct {
   358â†’		label string
   359â†’		ctx   TransitionContext
   360â†’	}
   361â†’
   362â†’	// For each phase/event, generate edges.
   363â†’	for _, phase := range allPhases {
   364â†’		for _, event := range allEvents {
   365â†’			var variants []contextVariant
   366â†’			switch {
   367â†’			case event == EventGitCommit && phase == PhaseEnded:
   368â†’				// HasFilesTouched only affects PhaseEnded transitions;
   369â†’				// other phases produce identical edges for both values.
   370â†’				variants = []contextVariant{
   371â†’					{"[files]", TransitionContext{HasFilesTouched: true}},
   372â†’					{"[no files]", TransitionContext{HasFilesTouched: false}},
   373â†’					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
   374â†’				}
   375â†’			case event == EventGitCommit:
   376â†’				variants = []contextVariant{
   377â†’					{"", TransitionContext{}},
   378â†’					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
   379â†’				}
   380â†’			default:
   381â†’				variants = []contextVariant{
   382â†’					{"", TransitionContext{}},
   383â†’				}
   384â†’			}
   385â†’
   386â†’			for _, v := range variants {
   387â†’				result := Transition(phase, event, v.ctx)
   388â†’
   389â†’				// Build edge label.
   390â†’				label := event.String()
   391â†’				if v.label != "" {
   392â†’					label += " " + v.label
   393â†’				}
   394â†’				if len(result.Actions) > 0 {
   395â†’					actionNames := make([]string, 0, len(result.Actions))
   396â†’					for _, a := range result.Actions {
   397â†’						actionNames = append(actionNames, a.String())
   398â†’					}
   399â†’					label += " / " + strings.Join(actionNames, ", ")
   400â†’				}
   401â†’
   402â†’				from := string(phase)
   403â†’				to := string(result.NewPhase)
   404â†’
   405â†’				fmt.Fprintf(&b, "    %s --> %s : %s\n", from, to, label)
   406â†’			}
   407â†’		}
   408â†’	}
   409â†’
   410â†’	return b.String()
   411â†’}
